import React from "react";

function App() {
  return (
    <div className="app">
      <div className="container">
        <h1>🚀 NoteFlow</h1>
        <p>Smart Notes App with MERN Stack</p>

        <div className="note-card">
          <h2>First Note</h2>
          <p>
            This is an advanced notes application with beautiful UI and backend
            integration.
          </p>

          <button>Create Note</button>
        </div>
      </div>
    </div>
  );
}

export default App;
